import SwiftUI
import CoreNFC

class NFCViewModel: NSObject, ObservableObject, NFCTagReaderSessionDelegate {
    @Published var isNFCAvailable = false
    @Published var statusMessage: String?
    @Published var isScanning = false
    @Published var lastScannedText: String?
    var nfcSession: NFCTagReaderSession?

    func checkAvailability() {
        isNFCAvailable = NFCTagReaderSession.readingAvailable
        if !isNFCAvailable { statusMessage = "NFC is not available on this device" }
        else { statusMessage = nil }
    }

    func startScan() {
        guard isNFCAvailable else { return }
        // REQUIRES PLIST: NFCReaderUsageDescription
        let session = NFCTagReaderSession(pollingOption: .iso14443, delegate: self, queue: nil)
        session.alertMessage = "Hold your iPhone near the tag"
        nfcSession = session
        session.begin()
        isScanning = true
    }

    func tagReaderSession(_ session: NFCTagReaderSession, didDetect tags: [NFCTag]) {
        guard let tag = tags.first else { return }
        session.connect(to: tag) { [weak self] error in
            guard let self = self else { return }
            if let error = error {
                session.invalidate(errorMessage: error.localizedDescription)
                DispatchQueue.main.async { self.isScanning = false; self.statusMessage = error.localizedDescription; self.nfcSession = nil }
                return
            }
            var text = "Tag read"
            if case .miFare(let m) = tag { text = m.identifier.map { String(format: "%02x", $0) }.joined() }
            else if case .iso15693(let i) = tag { text = i.identifier.map { String(format: "%02x", $0) }.joined() }
            session.invalidate()
            DispatchQueue.main.async { self.lastScannedText = text; self.isScanning = false; self.statusMessage = nil; self.nfcSession = nil }
        }
    }

    func tagReaderSession(_ session: NFCTagReaderSession, didInvalidateWithError error: Error?) {
        DispatchQueue.main.async {
            self.isScanning = false
            self.nfcSession = nil
            if let e = error as? NFCReaderError, e.code != .readerSessionInvalidationErrorUserCanceled { self.statusMessage = e.localizedDescription }
        }
    }
}

struct NFCView: View {
    @StateObject private var viewModel = NFCViewModel()

    var body: some View {
        VStack(spacing: 16) {
            if let message = viewModel.statusMessage {
                Text(message).foregroundStyle(.secondary)
            }
            Button("Scan") { viewModel.startScan() }
                .disabled(!viewModel.isNFCAvailable)
            if viewModel.isScanning {
                Text("Scanning...").foregroundStyle(.secondary)
            }
            if let text = viewModel.lastScannedText {
                Text(text).font(.caption)
            }
        }
        .onAppear { viewModel.checkAvailability() }
    }
}
